import{_ as i,o as t,c as s,a2 as a}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"Intégration & Envoi","description":"","frontmatter":{"title":"Intégration & Envoi"},"headers":[],"relativePath":"docs/fr/publishers/display-email/integration.md","filePath":"docs/fr/publishers/display-email/integration.md"}'),n={name:"docs/fr/publishers/display-email/integration.md"};function o(l,e,r,d,c,p){return t(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="integration-et-diffusion" tabindex="-1">Intégration et Diffusion <a class="header-anchor" href="#integration-et-diffusion" aria-label="Permalink to &quot;Intégration et Diffusion&quot;">​</a></h1><p>Le processus est rapide — assurez-vous simplement d&#39;utiliser le bon lien de redirection pour être payé.</p><hr><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Réception du visuel</h3><p>L&#39;annonceur vous transmet sa bannière (JPG, PNG ou GIF, max 150 Ko).</p><ul><li>Vérifiez que le format correspond à votre emplacement (ex : 600 × 150 px pour un Leaderboard).</li><li>Vérifiez la lisibilité sur mobile.</li></ul></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Récupération du Lien Tracké</h3><p>Sur <a href="https://app.getinside.media/" target="_blank">app.getinside.media</a>, ouvrez l&#39;onglet <strong>&quot;Configuration et suivi&quot;</strong> de la campagne et copiez le <strong>lien tracké</strong> (format <code>https://gtinsi.de/…</code>).</p><p><em>Contrairement à l&#39;email dédié, il n&#39;y a pas de pixel d&#39;ouverture à installer. Seuls les clics sont comptabilisés pour ce format.</em></p></div></div><div class="danger custom-block"><p class="custom-block-title">Lien tracké obligatoire</p><p>N&#39;utilisez <strong>jamais</strong> le lien brut de l&#39;annonceur. Sans le lien <code>gtinsi.de</code>, les clics ne sont pas comptabilisés et vous ne serez pas rémunéré.</p></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Insertion dans votre routeur</h3><p>Dans votre outil d&#39;emailing (Mailchimp, Brevo, Klaviyo…) :</p><ol><li>Insérez l&#39;image de l&#39;annonceur à l&#39;emplacement prévu.</li><li>Ajoutez un lien sur cette image.</li><li>Collez le lien tracké <code>gtinsi.de</code> comme URL de destination.</li></ol></div></div><div class="gi-step"><div class="gi-step-num">4</div><div class="gi-step-body"><h3>Test BAT &amp; Validation</h3><p>Envoyez un email de test à <code>benoit+news@getinside.fr</code> pour validation. Sur la plateforme, cliquez sur <strong>&quot;Valider la campagne&quot;</strong> puis attendez la validation côté annonceur.</p></div></div><div class="gi-step"><div class="gi-step-num done">✓</div><div class="gi-step-body"><h3>Diffusion &amp; Validation Finale</h3><p>Routez l&#39;email à votre base. Une fois l&#39;envoi terminé, retournez sur la plateforme et cliquez sur <strong>&quot;Valider la diffusion&quot;</strong>.</p></div></div><div class="warning custom-block"><p class="custom-block-title">Action bloquante — Valider la diffusion</p><p>Sans ce clic, les fonds restent séquestrés. C&#39;est cette action qui déclenche la facturation et le crédit sur votre Wallet (disponible 30 jours après la fin de campagne).</p></div>',10)])])}const v=i(n,[["render",o]]);export{m as __pageData,v as default};
